    gap: 10
  },
  secToggle: {
    color: '#e94560',
    fontWeight: 700,
    fontSize: 16,
    width: 20
  },
  secNum: {
    color: 'rgba(255,255,255,0.3)',
    fontSize: 12,
    fontWeight: 600
  },
  secTitle: {
    color: '#fff',
    fontWeight: 700,
    fontSize: 15
  },
  secCount: {
    color: 'rgba(255,255,255,0.35)',
    fontSize: 13
  },
  expMicroBadge: {
    background: 'rgba(200,150,0,0.1)',
    color: '#c8973a',
    fontSize: 10,
    padding: '2px 6px',
    borderRadius: 4,
    border: '1px solid rgba(200,150,0,0.2)'
  },
  lecList: {
    borderTop: '1px solid rgba(255,255,255,0.06)'
  },
  lecRow: (active, locked) => ({
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    padding: '12px 18px',
    cursor: locked ? 'not-allowed' : 'pointer',
    background: active ? 'rgba(233,69,96,0.08)' : 'transparent',
    opacity: locked ? 0.5 : 1,
    borderBottom: '1px solid rgba(255,255,255,0.04)'
  }),
  lecLeft: {
    display: 'flex',
    alignItems: 'center',
    gap: 12,
    flex: 1,
    minWidth: 0
  },
  lecIcon: {
    fontSize: 16,
    flexShrink: 0
  },
  lecTitle: active => ({
    color: active ? '#e94560' : '#fff',
    fontSize: 14,
    fontWeight: active ? 700 : 500,
    margin: 0
  }),
  lecDesc: {
    color: 'rgba(255,255,255,0.35)',
    fontSize: 12,
    margin: '3px 0 0',
    whiteSpace: 'nowrap',
    overflow: 'hidden',
    textOverflow: 'ellipsis',
    maxWidth: 400
  },
  lecRight: {
    display: 'flex',
    alignItems: 'center',
    gap: 8,
    flexShrink: 0
  },
  lecFree: {
    background: 'rgba(0,200,150,0.12)',
    color: '#00c896',
    border: '1px solid rgba(0,200,150,0.2)',
    borderRadius: 20,
    padding: '2px 8px',
    fontSize: 11,
    fontWeight: 600
  },
  lecOwned: {
    background: 'rgba(233,69,96,0.12)',
    color: '#e94560',
    border: '1px solid rgba(233,69,96,0.2)',
    borderRadius: 20,
    padding: '2px 8px',
    fontSize: 11,
    fontWeight: 600
  },
  lecDur: {
    color: 'rgba(255,255,255,0.3)',
    fontSize: 12
  },
  // استايلات "شراء التجربة" داخل السكشن
  expPrompt: {
    background: 'rgba(200,150,0,0.05)',
    padding: '16px',
    margin: '10px 18px',
    borderRadius: 10,
    border: '1px dashed rgba(200,150,0,0.3)',
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    flexWrap: 'wrap',
    gap: 12
  },
  expPromptInfo: {
    flex: 1,
    minWidth: 200
  },
  expPromptTitle: {
    color: '#c8973a',
    fontWeight: 700,
    margin: '0 0 4px',
    fontSize: 14
  },
  expPromptSub: {
    color: 'rgba(255,255,255,0.4)',
    fontSize: 12,
    margin: 0
  },
  expBuyBtn: {
    background: '#c8973a',
    color: '#000',
    border: 'none',
    borderRadius: 6,
    padding: '8px 16px',
    fontWeight: 700,
    fontSize: 13,
    cursor: 'pointer',
    fontFamily: 'Cairo,sans-serif'
  }
};
if (typeof document !== 'undefined' && !document.getElementById('cd-spin')) {
