// src/pages/courses/CourseDetail.js
import { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { coursesService } from '../../services/courses';
import { enrollmentsService } from '../../services/enrollments';
import { authService } from '../../services/auth';
import { experiencesService } from '../../services/experiences'; // استيراد خدمة التجارب
import api from '../../services/api';
import PaymentModal from '../payment/PaymentModal';

// ─── Video Player ─────────────────────────────────────────────────────────────
const VideoPlayer = ({ lecture }) => {
  const [streamUrl, setStreamUrl] = useState('');
  const [loading, setLoading] = useState(false);

  const getEmbedUrl = (url) => {
    if (!url) return null;
    const yt = url.match(/(?:youtube\.com\/watch\?v=|youtu\.be\/)([^&\s]+)/);
    if (yt) return `https://www.youtube.com/embed/${yt[1]}?autoplay=1`;
    const vm = url.match(/vimeo\.com\/(\d+)/);
    if (vm) return `https://player.vimeo.com/video/${vm[1]}?autoplay=1`;
    return null;
  };

  useEffect(() => {
    if (lecture?.video_type === 'upload' && lecture?.s3_key) {
      setLoading(true);
      api.get(`/courses/lectures/${lecture.id}/stream/`)
        .then(r => setStreamUrl(r.data.stream_url))
        .catch(console.error)
        .finally(() => setLoading(false));
    } else {
      setStreamUrl('');
    }
  }, [lecture?.id]);

  if (!lecture) return null;

  if (lecture.video_type === 'upload') {
    if (loading) return (
      <div style={vp.placeholder}>
        <div style={vp.spinner} />
        <p style={{ color: 'rgba(255,255,255,0.5)', marginTop: 16 }}>جاري تحميل الفيديو...</p>
      </div>
    );
    if (!streamUrl) return (
      <div style={vp.placeholder}>
        <span style={{ fontSize: 40 }}>❌</span>
        <p style={{ color: 'rgba(255,255,255,0.4)', marginTop: 12 }}>تعذّر تحميل الفيديو</p>
      </div>
    );
    return <video style={vp.video} controls controlsList="nodownload" autoPlay key={streamUrl}>
      <source src={streamUrl} />
    </video>;
  }

  const embedUrl = getEmbedUrl(lecture.video_url);
  if (!embedUrl) return (
    <div style={vp.placeholder}>
      <span style={{ fontSize: 40 }}>⚠️</span>
      <p style={{ color: 'rgba(255,255,255,0.4)', marginTop: 12 }}>رابط الفيديو غير صالح</p>
    </div>
  );
  return <iframe style={vp.iframe} src={embedUrl} title={lecture.title} allowFullScreen
    allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture" />;
};

const vp = {
  video: { width: '100%', display: 'block', background: '#000', maxHeight: 480, borderRadius: '0 0 12px 12px' },
  iframe: { width: '100%', height: 460, border: 'none', borderRadius: '0 0 12px 12px', display: 'block' },
  placeholder: { height: 360, display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', background: 'rgba(0,0,0,0.4)', borderRadius: '0 0 12px 12px' },
  spinner: { width: 40, height: 40, borderRadius: '50%', border: '3px solid rgba(255,255,255,0.1)', borderTopColor: '#e94560', animation: 'spin 0.8s linear infinite' },
};

// ─── Main Component ───────────────────────────────────────────────────────────
const CourseDetail = () => {
  const { id } = useParams();
  const navigate = useNavigate();

  const [course, setCourse] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [isEnrolled, setIsEnrolled] = useState(false);
  const [enrolling, setEnrolling] = useState(false);
  const [showPayment, setShowPayment] = useState(false);
  const [activeLecture, setActiveLecture] = useState(null);
  const [openSections, setOpenSections] = useState({});
  const [buyingExp, setBuyingExp] = useState(null); // لحالة شراء تجربة سكشن

  const user = JSON.parse(localStorage.getItem('user'));
  const isAdmin = user?.is_staff;
  const isInstructor = user?.is_instructor;
  const isOwner = isInstructor && course?.instructor === user?.id;
  const canWatch = isEnrolled || isAdmin || isOwner;

  useEffect(() => { loadCourse(); checkEnrollment(); }, [id]);

  const loadCourse = async () => {
    try {
      setLoading(true);
      const data = await coursesService.getById(id);
      setCourse(data);
      if (data.sections?.length) setOpenSections({ [data.sections[0].id]: true });
    } catch { setError('تعذّر تحميل الكورس'); }
    finally { setLoading(false); }
  };

  const checkEnrollment = async () => {
    if (!authService.isAuthenticated()) return;
    try { setIsEnrolled(await enrollmentsService.checkEnrollment(id)); } catch { }
  };

  const handleEnrollFree = async () => {
    if (!authService.isAuthenticated()) { navigate('/login'); return; }
    try {
      setEnrolling(true);
      await enrollmentsService.enroll(id);
      setIsEnrolled(true);
      await loadCourse();
    } catch (err) {
      alert(err.response?.data?.non_field_errors?.[0] || 'فشل التسجيل');
    } finally { setEnrolling(false); }
  };

  const handleBuyExperience = async (expId) => {
    if (!authService.isAuthenticated()) { navigate('/login'); return; }
    setBuyingExp(expId);
    try {
      await experiencesService.buy(expId);
      alert('✅ تم الاشتراك في تجربة السكشن بنجاح!');
      await loadCourse(); // تحديث البيانات لإظهار الوصول
    } catch (err) {
      alert('حدث خطأ أثناء عملية الشراء');
    } finally { setBuyingExp(null); }
  };

  const handlePaymentSuccess = async () => {
    setShowPayment(false); setIsEnrolled(true); await loadCourse();
  };

  const toggleSection = (sId) =>
    setOpenSections(p => ({ ...p, [sId]: !p[sId] }));

  const selectLecture = (lec, locked, expPurchased = false) => {
    // الطالب يقدر يشوف لو مشترك في الكورس أو لو دي تجربة سكشن وهو شاريها
    if (locked && !expPurchased) return;
    setActiveLecture(lec);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  if (loading) return (
    <div style={s.center}><div style={s.spinner} /></div>
  );
  if (error || !course) return (
    <div style={s.center}>
      <p style={{ color: 'rgba(255,255,255,0.4)', fontSize: 18 }}>{error || 'الكورس غير موجود'}</p>
    </div>
  );

  const isPaid = parseFloat(course.price) > 0;
  const price = parseFloat(course.price).toFixed(0);
  const totalLecs = course.sections?.reduce((a, s) => a + (s.lectures?.length || 0), 0) || 0;
  const totalMins = course.sections?.reduce((a, s) =>
    a + s.lectures?.reduce((b, l) => b + (l.duration_minutes || 0), 0), 0) || 0;

  return (
    <div style={s.page}>

      {/* ══ VIDEO PLAYER ══ */}
      {activeLecture && (canWatch || activeLecture.is_free_preview || activeLecture.exp_purchased) && (
        <div style={s.playerSection}>
          <div style={s.playerWrap}>
            <div style={s.playerHeader}>
              <button style={s.backLecBtn} onClick={() => setActiveLecture(null)}>✕ إغلاق</button>
              <span style={s.playerTitle}>▶ {activeLecture.title}</span>
              {activeLecture.is_free_preview && <span style={s.freeBadge}>معاينة مجانية</span>}
              {activeLecture.exp_purchased && <span style={s.ownedBadge}>تم شراء التجربة</span>}
            </div>
            <VideoPlayer lecture={activeLecture} />
          </div>
        </div>
      )}

      {/* ══ HERO ══ */}
      <div style={s.hero}>
        <div style={s.heroBlob} />
        <div style={s.heroInner}>

          {/* Left – info */}
          <div style={s.heroLeft}>
            <div style={s.breadcrumb}>
              <span style={s.breadLink} onClick={() => navigate('/courses')}>الكورسات</span>
              <span style={s.breadSep}>›</span>
              <span style={s.breadCurrent}>{course.title}</span>
            </div>

            <h1 style={s.courseTitle}>{course.title}</h1>
            <p style={s.courseDesc}>{course.description}</p>

            <div style={s.metaRow}>
              <span style={s.metaItem}>👤 {course.instructor_name || course.instructor_email}</span>
              <span style={s.metaDot}>·</span>
              <span style={s.metaItem}>📂 {course.total_sections || 0} قسم</span>
              <span style={s.metaDot}>·</span>
              <span style={s.metaItem}>🎬 {totalLecs} ليكتشر</span>
              {totalMins > 0 && <>
                <span style={s.metaDot}>·</span>
                <span style={s.metaItem}>⏱ {Math.round(totalMins / 60)} ساعة</span>
              </>}
            </div>

            <div style={s.badgeRow}>
              {isEnrolled && <span style={s.badgeEnrolled}>✓ مسجّل</span>}
              {isOwner && <span style={s.badgeOwner}>✏ كورسك</span>}
              {isAdmin && <span style={s.badgeAdmin}>🛡 أدمن</span>}
              {!isPaid && <span style={s.badgeFree}>مجاني</span>}
            </div>
          </div>

          {/* Right – card */}
          <div style={s.heroCard}>
            <div style={s.cardImgWrap}>
              {course.image_url
                ? <img src={course.image_url} alt={course.title} style={s.cardImg} />
                : <div style={s.cardImgPlaceholder}><span style={{ fontSize: 48, opacity: 0.3 }}>🎓</span></div>}
            </div>

            <div style={s.cardBody}>
              <div style={s.priceRow}>
                <span style={s.priceTag}>{isPaid ? `${price} EGP` : '🎁 مجاني'}</span>
              </div>

              {canWatch ? (
                <button style={s.ctaBtnGreen}
                  onClick={() => {
                    const first = course.sections?.[0]?.lectures?.[0];
                    if (first) selectLecture(first, false);
                    else document.getElementById('content-sec')?.scrollIntoView({ behavior: 'smooth' });
                  }}>
                  ▶ ابدأ التعلم الآن
                </button>
              ) : isPaid ? (
                <button style={s.ctaBtn}
                  onClick={() => { if (!user) { navigate('/login'); return; } setShowPayment(true); }}>
                  💳 اشتري الكورس كامل
                </button>
              ) : (
                <button style={s.ctaBtn} disabled={enrolling} onClick={handleEnrollFree}>
                  {enrolling ? '⏳ جاري التسجيل...' : '🎓 سجّل مجاناً الآن'}
                </button>
              )}

              {isOwner && (
                <button style={s.manageBtn} onClick={() => navigate(`/courses/${id}/manage`)}>
                  ⚙ إدارة محتوى الكورس
                </button>
              )}

              <div style={s.cardFeatures}>
                {[
                  ['📱', 'وصول من أي جهاز'],
                  ['♾', 'وصول مدى الحياة'],
                  ['🧪', 'تجارب سكاشن منفصلة'],
                ].map(([ico, txt]) => (
                  <div key={txt} style={s.feature}><span>{ico}</span><span>{txt}</span></div>
                ))}
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* ══ CONTENT ══ */}
      <div id="content-sec" style={s.contentSection}>
        <div style={s.contentInner}>

          {!canWatch && (
            <div style={s.lockNotice}>
              <span style={{ fontSize: 24 }}>🔒</span>
              <div>
                <p style={s.lockTitle}>{isPaid ? `محتوى الكورس مقفل` : 'سجّل مجاناً للوصول للمحتوى'}</p>
                <p style={s.lockSub}>يمكنك شراء الكورس كاملاً أو شراء "تجربة سكشن" معينة فقط من الأسفل.</p>
              </div>
            </div>
          )}

          <h2 style={s.contentTitle}>
            محتوى الكورس
            <span style={s.contentMeta}>{course.sections?.length || 0} أقسام · {totalLecs} ليكتشر</span>
          </h2>

          {course.sections?.map((sec, si) => {
            // التحقق من وجود تجربة مرتبطة بهذا السكشن
            const hasExperience = sec.experiences && sec.experiences.length > 0;
            const exp = hasExperience ? sec.experiences[0] : null;

            return (
              <div key={sec.id} style={s.secCard}>
                <div style={s.secHeader} onClick={() => toggleSection(sec.id)}>
                  <div style={s.secLeft}>
                    <span style={s.secToggle}>{openSections[sec.id] ? '▾' : '▸'}</span>
                    <span style={s.secNum}>القسم {si + 1}</span>
                    <span style={s.secTitle}>{sec.title}</span>
                  </div>
                  <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
                    {hasExperience && <span style={s.expMicroBadge}>🧪 تجربة متاحة</span>}
                    <span style={s.secCount}>{sec.lectures?.length || 0} ليكتشر</span>
                  </div>
                </div>

                {openSections[sec.id] && (
                  <div style={s.lecList}>
                    {sec.lectures?.map((lec) => {
                      const isFree = lec.is_free_preview;
                      const expPurchased = exp?.is_purchased;
                      const locked = !canWatch && !isFree && !expPurchased;
                      const isActive = activeLecture?.id === lec.id;

                      return (
                        <div key={lec.id} style={s.lecRow(isActive, locked)}
                          onClick={() => selectLecture({ ...lec, exp_purchased: expPurchased }, locked)}>
                          <div style={s.lecLeft}>
                            <span style={s.lecIcon}>
                              {locked ? '🔒' : isActive ? '▶' : '🎬'}
                            </span>
                            <div>
                              <p style={s.lecTitle(isActive)}>{lec.title}</p>
                              {lec.description && <p style={s.lecDesc}>{lec.description}</p>}
                            </div>
                          </div>
                          <div style={s.lecRight}>
                            {isFree && !canWatch && <span style={s.lecFree}>معاينة</span>}
                            {expPurchased && !canWatch && <span style={s.lecOwned}>بناءً على التجربة</span>}
                            {lec.duration_minutes > 0 && <span style={s.lecDur}>{lec.duration_minutes} د</span>}
                          </div>
                        </div>
                      );
                    })}

                    {/* عرض خيار شراء التجربة إذا لم يكن الطالب مسجلاً في الكورس */}
                    {hasExperience && !canWatch && !exp.is_purchased && (
                      <div style={s.expPrompt}>
                        <div style={s.expPromptInfo}>
                          <p style={s.expPromptTitle}>🧪 فاتك السكشن ده؟</p>
                          <p style={s.expPromptSub}>تقدر تشتري "تجربة السكشن" دي بس وتشوف حلول المسائل والشرح الخاص بيها.</p>
                        </div>
                        <button 
                          style={s.expBuyBtn} 
                          onClick={() => handleBuyExperience(exp.id)}
                          disabled={buyingExp === exp.id}
                        >
                          {buyingExp === exp.id ? '...' : `فتح السكشن بـ ${exp.effective_price} EGP`}
                        </button>
                      </div>
                    )}
                  </div>
                )}
              </div>
            );
          })}
        </div>
      </div>

      {showPayment && (
        <PaymentModal course={course} onSuccess={handlePaymentSuccess} onClose={() => setShowPayment(false)} />
      )}
    </div>
  );
};

// ─── Styles ───────────────────────────────────────────────────────────────────
const s = {
  page: { background: '#0f0f1a', minHeight: '100vh', direction: 'rtl' },
  center: { display: 'flex', justifyContent: 'center', alignItems: 'center', minHeight: '60vh', background: '#0f0f1a' },
  spinner: { width: 44, height: 44, borderRadius: '50%', border: '3px solid rgba(255,255,255,0.1)', borderTopColor: '#e94560', animation: 'spin 0.8s linear infinite' },

  playerSection: { background: '#000', borderBottom: '1px solid rgba(255,255,255,0.08)' },
  playerWrap: { maxWidth: 900, margin: '0 auto' },
  playerHeader: { display: 'flex', alignItems: 'center', gap: 12, padding: '12px 16px', background: 'rgba(255,255,255,0.04)' },
  backLecBtn: { background: 'rgba(255,255,255,0.08)', border: 'none', color: 'rgba(255,255,255,0.6)', borderRadius: 6, padding: '5px 12px', cursor: 'pointer', fontSize: 13, fontFamily: 'Cairo,sans-serif' },
  playerTitle: { color: '#fff', fontWeight: 700, fontSize: 15, flex: 1, textAlign: 'right' },
  freeBadge: { background: 'rgba(0,200,150,0.15)', color: '#00c896', border: '1px solid rgba(0,200,150,0.3)', borderRadius: 20, padding: '3px 10px', fontSize: 12, fontWeight: 600 },
  ownedBadge: { background: 'rgba(233,69,96,0.15)', color: '#e94560', border: '1px solid rgba(233,69,96,0.3)', borderRadius: 20, padding: '3px 10px', fontSize: 12, fontWeight: 600 },

  hero: { background: 'linear-gradient(160deg, #0f0f1a 0%, #1a1a2e 50%, #0f3460 100%)', padding: '60px 20px 70px', position: 'relative', overflow: 'hidden' },
  heroBlob: { position: 'absolute', width: 600, height: 600, borderRadius: '50%', background: 'radial-gradient(circle, rgba(233,69,96,0.08) 0%, transparent 70%)', top: -100, right: -100, pointerEvents: 'none' },
  heroInner: { maxWidth: 1100, margin: '0 auto', display: 'flex', gap: 48, alignItems: 'flex-start', flexWrap: 'wrap', position: 'relative', zIndex: 1 },

  heroLeft: { flex: 1, minWidth: 300, textAlign: 'right' },
  breadcrumb: { display: 'flex', alignItems: 'center', gap: 8, marginBottom: 20, justifyContent: 'flex-start' },
  breadLink: { color: 'rgba(255,255,255,0.4)', fontSize: 13, cursor: 'pointer' },
  breadSep: { color: 'rgba(255,255,255,0.2)', fontSize: 13 },
  breadCurrent: { color: 'rgba(255,255,255,0.7)', fontSize: 13 },
  courseTitle: { color: '#fff', fontSize: 'clamp(22px,3.5vw,38px)', fontWeight: 900, lineHeight: 1.2, margin: '0 0 16px' },
  courseDesc: { color: 'rgba(255,255,255,0.55)', fontSize: 15, lineHeight: 1.8, margin: '0 0 24px', maxWidth: 620 },
  metaRow: { display: 'flex', flexWrap: 'wrap', alignItems: 'center', gap: 8, marginBottom: 20, justifyContent: 'flex-start' },
  metaItem: { color: 'rgba(255,255,255,0.55)', fontSize: 14 },
  metaDot: { color: 'rgba(255,255,255,0.2)' },
  badgeRow: { display: 'flex', gap: 8, flexWrap: 'wrap', justifyContent: 'flex-start' },
  badgeEnrolled: { background: 'rgba(0,200,150,0.15)', color: '#00c896', border: '1px solid rgba(0,200,150,0.25)', borderRadius: 20, padding: '4px 12px', fontSize: 12, fontWeight: 700 },
  badgeOwner: { background: 'rgba(100,100,255,0.12)', color: '#8888ff', border: '1px solid rgba(100,100,255,0.25)', borderRadius: 20, padding: '4px 12px', fontSize: 12, fontWeight: 700 },
  badgeAdmin: { background: 'rgba(255,200,0,0.1)', color: '#f5c542', border: '1px solid rgba(245,197,66,0.25)', borderRadius: 20, padding: '4px 12px', fontSize: 12, fontWeight: 700 },
